export const getAsyncApiDiffCase = (section: string, caseId: string): AsyncApiDiffCase | undefined => {
  return asyncApiDiffCases.find((item) => item.section === section && item.caseId === caseId);
};

export const getAsyncApiDiffCasesBySection = (section: string): AsyncApiDiffCase[] => {
  return asyncApiDiffCases.filter((item) => item.section === section);
};
